CREATE TABLE IF NOT EXISTS "User" (
    "id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "username" TEXT NOT NULL UNIQUE,
    "email" TEXT NOT NULL UNIQUE,
    "passwordHash" TEXT NOT NULL,
    "role" TEXT NOT NULL,
    "enabled" BOOLEAN NOT NULL,
    "createdAt" TIMESTAMP NOT NULL DEFAULT NOW(),
    PRIMARY KEY ("id")
);

COMMENT ON COLUMN "User"."role" IS 'PLAYER
ORGANIZER
ADMIN';

CREATE TABLE IF NOT EXISTS "GameTypes" (
    "id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "name" TEXT NOT NULL,
    "code" TEXT NOT NULL UNIQUE,
    "description" TEXT,
    "isActive" BOOLEAN NOT NULL DEFAULT FALSE,
    PRIMARY KEY ("id")
);

CREATE TABLE IF NOT EXISTS "PlayerProfile" (
    "id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "gameId" INTEGER NOT NULL,
    "userId" INTEGER NOT NULL UNIQUE,
    "nickname" TEXT NOT NULL,
    "description" TEXT,
    "country" TEXT NOT NULL,
    "rating" DECIMAL(5, 2) NOT NULL DEFAULT 0,
    PRIMARY KEY ("id"),
    FOREIGN KEY ("userId") REFERENCES "User"("id") ON UPDATE CASCADE ON DELETE CASCADE,
    FOREIGN KEY ("gameId") REFERENCES "GameTypes"("id") ON UPDATE CASCADE ON DELETE RESTRICT
);

CREATE TABLE IF NOT EXISTS "Team" (
    "id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "name" TEXT NOT NULL,
    "createdAt" TIMESTAMP NOT NULL DEFAULT NOW(),
    "captainId" INTEGER,
    PRIMARY KEY ("id"),
    FOREIGN KEY ("captainId") REFERENCES "PlayerProfile"("id") ON UPDATE CASCADE ON DELETE SET NULL
);

CREATE TABLE IF NOT EXISTS "TeamMembers" (
    "id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "playerId" INTEGER NOT NULL,
    "teamId" INTEGER NOT NULL,
    "role" TEXT NOT NULL,
    "joinedAt" TIMESTAMP NOT NULL DEFAULT NOW(),
    PRIMARY KEY ("id"),
    UNIQUE ("teamId", "playerId"),
    FOREIGN KEY ("playerId") REFERENCES "PlayerProfile"("id") ON UPDATE CASCADE ON DELETE CASCADE,
    FOREIGN KEY ("teamId") REFERENCES "Team"("id") ON UPDATE CASCADE ON DELETE CASCADE
);

COMMENT ON COLUMN "TeamMembers"."role" IS 'CAPTAIN
MEMBER';

CREATE TABLE IF NOT EXISTS "Tournament" (
    "id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "title" TEXT NOT NULL UNIQUE,
    "description" TEXT NOT NULL,
    "participantType" TEXT NOT NULL,
    "access" TEXT NOT NULL,
    "gameType" INTEGER NOT NULL,
    "status" TEXT NOT NULL,
    "organizerId" INTEGER NOT NULL,
    "startDate" TIMESTAMP NOT NULL,
    "registrationDeadline" TIMESTAMP,
    "maxParticipants" INTEGER,
    "createdAt" TIMESTAMP NOT NULL DEFAULT NOW(),
    PRIMARY KEY ("id"),
    FOREIGN KEY ("organizerId") REFERENCES "User"("id") ON UPDATE CASCADE ON DELETE RESTRICT,
    FOREIGN KEY ("gameType") REFERENCES "GameTypes"("id") ON UPDATE CASCADE ON DELETE RESTRICT
);

COMMENT ON COLUMN "Tournament"."participantType" IS 'SOLO
TEAM';
COMMENT ON COLUMN "Tournament"."access" IS 'OPEN
INVITE';
COMMENT ON COLUMN "Tournament"."status" IS 'DRAFT
REGISTRATION_OPEN
IN_PROGRESS
FINISHED
CANCELLED';
COMMENT ON COLUMN "Tournament"."maxParticipants" IS 'Уникальное количество игроков/команд';

CREATE TABLE IF NOT EXISTS "TournamentSoloParticipant" (
    "id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "tournamentId" INTEGER NOT NULL,
    "playerProfileId" INTEGER NOT NULL,
    "status" TEXT NOT NULL,
    "seed" INTEGER NOT NULL,
    "joinedAt" TIMESTAMP NOT NULL DEFAULT NOW(),
    "finalPlace" INTEGER,
    PRIMARY KEY ("id"),
    UNIQUE ("tournamentId", "playerProfileId"),
    FOREIGN KEY ("tournamentId") REFERENCES "Tournament"("id") ON UPDATE CASCADE ON DELETE CASCADE,
    FOREIGN KEY ("playerProfileId") REFERENCES "PlayerProfile"("id") ON UPDATE CASCADE ON DELETE CASCADE
);

COMMENT ON COLUMN "TournamentSoloParticipant"."seed" IS 'Используется для формирования сетки.';

CREATE TABLE IF NOT EXISTS "TournamentTeamParticipant" (
    "id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "tournamentId" INTEGER NOT NULL,
    "teamId" INTEGER NOT NULL,
    "status" TEXT NOT NULL,
    "seed" INTEGER NOT NULL,
    "joinedAt" TIMESTAMP NOT NULL DEFAULT NOW(),
    "finalPlace" INTEGER,
    PRIMARY KEY ("id"),
    UNIQUE ("tournamentId", "teamId"),
    FOREIGN KEY ("tournamentId") REFERENCES "Tournament"("id") ON UPDATE CASCADE ON DELETE CASCADE,
    FOREIGN KEY ("teamId") REFERENCES "Team"("id") ON UPDATE CASCADE ON DELETE CASCADE
);

COMMENT ON COLUMN "TournamentTeamParticipant"."seed" IS 'Используется для формирования сетки.';

CREATE TABLE IF NOT EXISTS "MatchSolo" (
    "id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "tournamentId" INTEGER NOT NULL,
    "roundNumber" INTEGER,
    "player1Id" INTEGER NOT NULL,
    "player2Id" INTEGER NOT NULL,
    "winnerPlayerId" INTEGER,
    "status" TEXT NOT NULL,
    "scheduledAt" TIMESTAMP,
    "nextMatchId" INTEGER,
    PRIMARY KEY ("id"),
    FOREIGN KEY ("tournamentId") REFERENCES "Tournament"("id") ON UPDATE CASCADE ON DELETE CASCADE,
    FOREIGN KEY ("player1Id") REFERENCES "PlayerProfile"("id") ON UPDATE CASCADE ON DELETE RESTRICT,
    FOREIGN KEY ("player2Id") REFERENCES "PlayerProfile"("id") ON UPDATE CASCADE ON DELETE RESTRICT,
    FOREIGN KEY ("winnerPlayerId") REFERENCES "PlayerProfile"("id") ON UPDATE CASCADE ON DELETE SET NULL,
    FOREIGN KEY ("nextMatchId") REFERENCES "MatchSolo"("id") ON UPDATE CASCADE ON DELETE SET NULL
);

COMMENT ON COLUMN "MatchSolo"."status" IS 'SCHEDULED
IN_PROGRESS
FINISHED
CANCELLED';

CREATE TABLE IF NOT EXISTS "MatchTeam" (
    "id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
    "tournamentId" INTEGER NOT NULL,
    "roundNumber" INTEGER,
    "team1Id" INTEGER NOT NULL,
    "team2Id" INTEGER NOT NULL,
    "winnerTeamId" INTEGER,
    "status" TEXT NOT NULL,
    "scheduledAt" TIMESTAMP,
    "nextMatchId" INTEGER,
    PRIMARY KEY ("id"),
    FOREIGN KEY ("tournamentId") REFERENCES "Tournament"("id") ON UPDATE CASCADE ON DELETE CASCADE,
    FOREIGN KEY ("team1Id") REFERENCES "Team"("id") ON UPDATE CASCADE ON DELETE RESTRICT,
    FOREIGN KEY ("team2Id") REFERENCES "Team"("id") ON UPDATE CASCADE ON DELETE RESTRICT,
    FOREIGN KEY ("winnerTeamId") REFERENCES "Team"("id") ON UPDATE CASCADE ON DELETE SET NULL,
    FOREIGN KEY ("nextMatchId") REFERENCES "MatchTeam"("id") ON UPDATE CASCADE ON DELETE SET NULL
);

COMMENT ON COLUMN "MatchTeam"."status" IS 'SCHEDULED
IN_PROGRESS
FINISHED
CANCELLED';
